boolean intersection(Line2d l, Point2d p) {
		// The polynomial judgement
		double D = (a * l.b) - (b * l.a);
		if (D == 0) {
			p.x = 0;
			p.y = 0;
			return false;
		} else {
			p.x = (c * l.b - b * l.c) / D / 1.0;
			p.y = (a * l.c - c * l.a) / D / 1.0;
			return true;
		}
	}

