					int n = JOptionPane.showConfirmDialog(App.getFrame(), Local.getString("This project is already exists and will be replaced.\nContinue?"), Local.getString("Project is already exists"), JOptionPane.YES_NO_OPTION);
					if (n != JOptionPane.YES_OPTION) {
						zip.close();
						return;
					}
					ProjectManager.removeProject(pId);
				}
				Project prj = ProjectManager.createProject(pId, pTitle, new CalendarDate(pStartD), null);
				if (pEndD != null) {
					prj.setEndDate(new CalendarDate(pEndD));
				}
				// File prDir = new File(JN_DOCPATH + prj.getID());
				Enumeration files;
				for (files = zip.entries(); files.hasMoreElements();) {
