private Map<String, Integer> findShortNames(Class<?> clazz, String prefix) {
        final int prefixLength = prefix.length();
        Map<String, Integer> shortNames = new HashMap<>();
        for (Field field : clazz.getFields()) {
            String name = field.getName();
            if (shortNames.contains(name) && !shortNames.contains(prefix)) {
                continue;
            }

            try {
                int value = field.getInt(null);
                String shortName = name.substring(prefixLength);
                if (!shortNames.contains(shortName) && !shortNames.contains(prefix)) {
                    shortNames.put(shortName, value);
                }
            } catch (IllegalAccessException ignored) {
                // ignore field
            }
        }
        return shortNames;
    }

